with open("./output/ligand_preparation/lig_charged.pdbqt") as f:
    lines = f.readlines()

total_q = 0.0
atoms = []
for line in lines:
    if line.startswith(('ATOM', 'HETATM')):
        # PDBQT: columns are different, use split
        parts = line.split()
        q = float(parts[-2])  # charge is second to last
        total_q += q
        atoms.append((parts[3], q))

print(f"Total PDBQT charge: {total_q:.3f}")
print(f"Number of atoms: {len(atoms)}")

print("\nActive torsions:")
for line in lines:
    if "torsions" in line:
        print(line.strip())

print("\nStructure tree:")
for line in lines:
    if line.startswith(('ROOT', 'ENDROOT', 'BRANCH', 'END')):
        print(line.strip())
PYEOF"}
